            let parsed_error = parse_chat_error(&error_text, None);
            let assistant_tool_call_msg = build_tool_call_assistant_message(
                tool_call_id.clone(),
                "exec",
                Some(tool_args.clone()),
                client_seq,
                Some(run_id),
