        let text = r#"Let me check that.
```tool_call
{"tool": "exec", "arguments": {"command": "ls -la"}}
```
Done."#;
        let (calls, remaining) = parse_tool_calls_from_text(text);
        assert_eq!(calls.len(), 1);
        assert_eq!(calls[0].name, "exec");
